import boto3
import json
import pymysql
from urllib.parse import unquote_plus

rds_instance = 'your-rds-instance'
rds_username = 'your-rds-username'
rds_password = 'your-rds-password'

def lambda_handler(event, context):
    try:
        search_params = event['queryStringParameters']
        
        # Unescape any special characters in the query parameters
        for key, value in search_params.items():
            search_params[key] = unquote_plus(value)
            
        # Build SQL query dynamically based on the search parameters
        sql_query = "SELECT * FROM products WHERE 1=1"
        
        if 'name' in search_params:
            sql_query += " AND name LIKE '%{}%'".format(search_params['name'])
            
        if 'category' in search_params:
            sql_query += " AND category = '{}'".format(search_params['category'])
            
        if 'price' in search_params:
            sql_query += " AND price BETWEEN {} AND {}".format(search_params['price'], search_params['price'])
        
        # Establish a connection to the RDS database
        conn = pymysql.connect(rds_instance, user=rds_username, password=rds_password)
        
        # Create a cursor object to execute SQL queries
        cur = conn.cursor()
        
        # Execute the dynamic SQL query
        cur.execute(sql_query)
        
        # Fetch all results from the query
        products = cur.fetchall()
        
        # Close the database connection
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    
    except Exception as e:
        print(e)
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

